// コーラすごろく

let CONFIG;
let TEXT;
let INGREDIENTS;
let EVENT_DIE;
let RESULT_WORDS;
let BOARD_NODES;
let gameState;
let layout;

var ROUND = "round";
var SQUARE = "square";
var PROJECT = "project";

let lastLayoutWidth = 0;
let lastLayoutHeight = 0;

/*
 * 最終フレームルーターが使う、補充完了画面専用の入口。
 * 画面機能側が一度だけ登録し、draw / touched 自体を上書きしない。
 */
let colaRollDeliveryCompleteDrawHandler = null;
let colaRollDeliveryCompleteTouchHandler = null;

/*
 * 最終フレームルーターが使う、補充先画面専用の入口。
 * 補充先フロー側が一度だけ登録し、draw / touched 自体を上書きしない。
 */
let colaRollDispatchDrawHandler = null;
let colaRollDispatchTouchHandler = null;
let colaRollFactoryStartupFadeHandler = null;

function setupCore() {
    rectMode(CORNER);
    ellipseMode(CENTER);
    textAlign(CENTER);
    initializeGameFonts();

    installGameDebugErrorOverlay();

    const workLabel = typeof document !== "undefined"
        ? document.getElementById("workLabel")
        : null;

    if (workLabel) {
        workLabel.style.display = "none";
    }

    initGameData();
    applyVisualSystemConfig();
    applyBottleProductionTerminology();
    applyBoardReadabilityConfig();
    applyFactoryLineBoardLayout();
    initCapPowerConfig();
    initGameState();
    updateLayout(true);
    installBottleGarnishTrayPlacement();

    gameState.debugLastPhase =
        gameState.phase;

    gameState.debugLastError =
        null;
}

const setupCoreBaseForTitleWorkshopBackground =
    setupCore;

setupCore = function() {
    const result =
        setupCoreBaseForTitleWorkshopBackground.apply(
            this,
            arguments
        );

    initColaRollTitleWorkshopBackground();

    return result;
};


function installColaRollBoardIconRefresh() {
    const root =
        typeof globalThis !== "undefined"
            ? globalThis
            : (
                typeof window !== "undefined"
                    ? window
                    : {}
            );

    if (
        root.__colaRollBoardIconRefreshInstalled
    ) {
        return;
    }

    if (
        typeof drawNodeIcon !== "function"
    ) {
        return;
    }

    root.__colaRollBoardIconRefreshInstalled =
        true;

    function drawAdjustmentBoardIcon(
        x,
        y,
        size,
        alpha
    ) {
        pushMatrix();
        translate(x, y);

        rectMode(CENTER);
        ellipseMode(CENTER);

        /*
         * 外側の受け皿。
         * 通常素材マスより少し無機質にする。
         */
        noStroke();
        fill(
            54,
            44,
            40,
            alpha * 0.95
        );
        ellipse(
            0,
            0,
            size * 1.05,
            size * 1.05
        );

        /*
         * 金属プレート
         */
        fill(
            164,
            151,
            138,
            alpha * 0.95
        );
        rect(
            0,
            0,
            size * 0.92,
            size * 0.70,
            size * 0.11
        );

        fill(
            108,
            97,
            88,
            alpha * 0.90
        );
        rect(
            0,
            0,
            size * 0.78,
            size * 0.56,
            size * 0.08
        );

        /*
         * 左右ガイド
         */
        stroke(
            231,
            206,
            171,
            alpha * 0.85
        );
        strokeWeight(
            Math.max(
                1.2,
                size * 0.05
            )
        );

        /*
         * 左: 順番替え
         */
        line(
            -size * 0.27,
            0,
            -size * 0.15,
            0
        );
        line(
            -size * 0.27,
            -size * 0.08,
            -size * 0.20,
            0
        );
        line(
            -size * 0.27,
            size * 0.08,
            -size * 0.20,
            0
        );

        line(
            -size * 0.05,
            0,
            -size * 0.17,
            0
        );
        line(
            -size * 0.05,
            -size * 0.08,
            -size * 0.12,
            0
        );
        line(
            -size * 0.05,
            size * 0.08,
            -size * 0.12,
            0
        );

        /*
         * 右: 返し仕込み
         */
        line(
            size * 0.20,
            -size * 0.14,
            size * 0.20,
            size * 0.14
        );
        line(
            size * 0.14,
            -size * 0.08,
            size * 0.20,
            -size * 0.14
        );
        line(
            size * 0.26,
            -size * 0.08,
            size * 0.20,
            -size * 0.14
        );

        line(
            size * 0.14,
            size * 0.08,
            size * 0.20,
            size * 0.14
        );
        line(
            size * 0.26,
            size * 0.08,
            size * 0.20,
            size * 0.14
        );

        /*
         * 中央レバー
         */
        stroke(
            34,
            25,
            21,
            alpha
        );
        strokeWeight(
            Math.max(
                2.2,
                size * 0.09
            )
        );
        line(
            0,
            size * 0.10,
            0,
            -size * 0.16
        );

        noStroke();
        fill(
            241,
            183,
            93,
            alpha
        );
        ellipse(
            0,
            -size * 0.18,
            size * 0.16,
            size * 0.16
        );

        fill(
            87,
            58,
            39,
            alpha
        );
        ellipse(
            0,
            size * 0.12,
            size * 0.14,
            size * 0.14
        );

        /*
         * 小ランプ
         */
        fill(
            246,
            205,
            109,
            alpha * 0.95
        );
        ellipse(
            0,
            size * 0.28,
            size * 0.11,
            size * 0.11
        );

        fill(
            255,
            241,
            196,
            alpha * 0.85
        );
        ellipse(
            0,
            size * 0.28,
            size * 0.05,
            size * 0.05
        );

        popMatrix();
    }

    function drawSpillBoardIcon(
        x,
        y,
        size,
        alpha
    ) {
        pushMatrix();
        translate(x, y);

        rectMode(CENTER);
        ellipseMode(CENTER);

        /*
         * 暗い事故跡の土台
         */
        noStroke();
        fill(
            68,
            28,
            25,
            alpha * 0.92
        );
        ellipse(
            0,
            0,
            size * 1.08,
            size * 1.08
        );

        /*
         * 赤い警告リング
         */
        noFill();
        stroke(
            201,
            74,
            58,
            alpha * 0.95
        );
        strokeWeight(
            Math.max(
                2.0,
                size * 0.08
            )
        );
        ellipse(
            0,
            0,
            size * 0.94,
            size * 0.94
        );

        /*
         * 傾いた瓶
         */
        pushMatrix();
        rotate(-0.55);

        fill(
            219,
            197,
            167,
            alpha * 0.95
        );
        stroke(
            82,
            56,
            41,
            alpha * 0.70
        );
        strokeWeight(
            Math.max(
                1.1,
                size * 0.04
            )
        );

        rect(
            -size * 0.04,
            -size * 0.02,
            size * 0.19,
            size * 0.37,
            size * 0.05
        );

        noStroke();
        fill(
            84,
            42,
            27,
            alpha * 0.92
        );
        rect(
            -size * 0.04,
            size * 0.03,
            size * 0.15,
            size * 0.20,
            size * 0.04
        );

        fill(
            161,
            118,
            73,
            alpha * 0.95
        );
        rect(
            -size * 0.04,
            -size * 0.19,
            size * 0.09,
            size * 0.08,
            size * 0.03
        );

        popMatrix();

        /*
         * こぼれた液
         */
        noStroke();
        fill(
            143,
            47,
            34,
            alpha * 0.90
        );

        ellipse(
            size * 0.08,
            size * 0.18,
            size * 0.34,
            size * 0.18
        );

        ellipse(
            size * 0.24,
            size * 0.28,
            size * 0.13,
            size * 0.18
        );

        ellipse(
            size * 0.02,
            size * 0.31,
            size * 0.10,
            size * 0.14
        );

        /*
         * はみ出す滴で事故感を出す
         */
        ellipse(
            size * 0.34,
            size * 0.42,
            size * 0.09,
            size * 0.12
        );

        /*
         * 警告バッジ
         */
        fill(
            232,
            191,
            92,
            alpha * 0.98
        );
        ellipse(
            -size * 0.26,
            -size * 0.25,
            size * 0.20,
            size * 0.20
        );

        fill(
            109,
            48,
            33,
            alpha
        );
        rect(
            -size * 0.26,
            -size * 0.25,
            size * 0.035,
            size * 0.10,
            size * 0.01
        );
        ellipse(
            -size * 0.26,
            -size * 0.18,
            size * 0.035,
            size * 0.035
        );

        popMatrix();
    }

    const drawNodeIconBaseForBoardIconRefresh =
        drawNodeIcon;

    drawNodeIcon = function(
        node,
        x,
        y,
        size,
        alpha
    ) {
        if (
            node &&
            node.eventKind === "adjustment"
        ) {
            drawAdjustmentBoardIcon(
                x,
                y,
                size,
                alpha
            );
            return;
        }

        if (
            node &&
            node.eventKind === "spill"
        ) {
            drawSpillBoardIcon(
                x,
                y,
                size,
                alpha
            );
            return;
        }

        return drawNodeIconBaseForBoardIconRefresh(
            node,
            x,
            y,
            size,
            alpha
        );
    };
}






function installLemonPeelSeparation() {
    if (
        !gameState ||
        gameState.lemonPeelSeparationInstalled
    ) {
        return;
    }

    gameState.lemonPeelSeparationInstalled =
        true;

    /*
     * 1. ガーニッシュ取得時の名称
     *
     * lemon はレモン。
     * lemon_peel と取り違えない。
     */
    const startGarnishGetPopupBaseForLemonName =
        startGarnishGetPopup;

    startGarnishGetPopup = function(
        garnish,
        onComplete
    ) {
        startGarnishGetPopupBaseForLemonName(
            garnish,
            onComplete
        );

        if (
            garnish !== "lemon" ||
            !gameState.ingredientGetEffect
        ) {
            return;
        }

        gameState.ingredientGetEffect.displayName =
            gameState.language === "ja"
                ? "レモン"
                : "Lemon";
    };


    /*
     * 2. 盤面のレモンピール・ステーション
     *
     * spice_lemon は、
     * 黄色い瓶の中に巻いた皮が入っている見た目にする。
     *
     * safe_lemon の輪切りレモンとは、
     * 盤面だけでも区別できる。
     */
    const drawBoardStationIconBaseForLemonPeel =
        drawBoardStationIcon;

    drawBoardStationIcon = function(
        node,
        x,
        y,
        size,
        alpha
    ) {
        const isLemonPeelStation =
            node &&
            node.effect &&
            node.effect.addIngredient ===
                "lemon_peel";

        if (!isLemonPeelStation) {
            return drawBoardStationIconBaseForLemonPeel(
                node,
                x,
                y,
                size,
                alpha
            );
        }

        const drawn =
            drawBoardStationIconBaseForLemonPeel(
                node,
                x,
                y,
                size,
                alpha
            );

        const active =
            gameState.currentNodeId ===
            node.id;

        pushMatrix();

        translate(
            x,
            y
        );

        scale(
            size / 24,
            size / 24
        );

        /*
         * 元の香辛料アイコンを、
         * ステーション台座ごと上から描き直す。
         */
        drawBoardStationBase(
            alpha,
            active
        );

        rectMode(CENTER);
        noStroke();

        /*
         * 瓶のふた
         */
        fill(
            46,
            31,
            22,
            alpha
        );

        rect(
            0,
            -6,
            9,
            4,
            1
        );

        /*
         * 黄色い瓶
         */
        fill(
            209,
            190,
            48,
            alpha * 0.96
        );

        rect(
            0,
            1,
            14,
            12,
            3
        );

        /*
         * 瓶の反射
         */
        fill(
            255,
            240,
            116,
            alpha * 0.26
        );

        rect(
            -4,
            0,
            2,
            8,
            1
        );

        /*
         * レモンピールの影
         */
        noFill();

        strokeCap(ROUND);

        stroke(
            96,
            79,
            18,
            alpha * 0.92
        );

        strokeWidth(2.5);

        line(
            -4.6,
            3.2,
            -2.6,
            4.9
        );

        line(
            -2.6,
            4.9,
            1.7,
            4.2
        );

        line(
            1.7,
            4.2,
            3.7,
            1.3
        );

        line(
            3.7,
            1.3,
            1.5,
            -1.7
        );

        line(
            1.5,
            -1.7,
            -2.1,
            -1.1
        );

        /*
         * レモンピールの黄色い面
         */
        stroke(
            255,
            239,
            111,
            alpha
        );

        strokeWidth(1.15);

        line(
            -4.3,
            3.1,
            -2.3,
            4.3
        );

        line(
            -2.3,
            4.3,
            1.5,
            3.7
        );

        line(
            1.5,
            3.7,
            2.9,
            1.2
        );

        line(
            2.9,
            1.2,
            1.1,
            -1.1
        );

        line(
            1.1,
            -1.1,
            -1.7,
            -0.7
        );

        /*
         * 瓶の輪郭
         */
        noFill();

        stroke(
            237,
            196,
            126,
            alpha * 0.78
        );

        strokeWidth(1.1);

        rect(
            0,
            1,
            14,
            12,
            3
        );

        noStroke();
        rectMode(CORNER);

        popMatrix();

        return drawn;
    };


    /*
     * 3. 完成グラス
     *
     * lemon      = グラスの縁の輪切り
     * lemon_peel = 液面近くの細いカール
     */
    const drawFinishedColaFeatureBaseForLemonPeel =
        drawFinishedColaFeature;

    drawFinishedColaFeature = function(
        featureId,
        featureIndex,
        liquidTop,
        topW,
        glassH,
        alpha
    ) {
        if (
            featureId !==
            "lemon_peel"
        ) {
            return drawFinishedColaFeatureBaseForLemonPeel(
                featureId,
                featureIndex,
                liquidTop,
                topW,
                glassH,
                alpha
            );
        }

        const side =
            featureIndex === 0
                ? -1
                : 1;

        const x =
            side *
            topW *
            0.20;

        const y =
            liquidTop +
            10;

        pushMatrix();

        translate(
            x,
            y
        );

        rotate(
            side * 18
        );

        strokeCap(ROUND);
        noFill();

        /*
         * ピールの濃い縁
         */
        stroke(
            102,
            82,
            19,
            alpha * 0.92
        );

        strokeWidth(5.6);

        line(
            -10,
            5,
            -11,
            0
        );

        line(
            -11,
            0,
            -8,
            -5
        );

        line(
            -8,
            -5,
            -2,
            -6
        );

        line(
            -2,
            -6,
            4,
            -3
        );

        line(
            4,
            -3,
            6,
            2
        );

        line(
            6,
            2,
            3,
            6
        );

        line(
            3,
            6,
            -3,
            6
        );

        /*
         * ピールの黄色い面
         */
        stroke(
            239,
            221,
            70,
            alpha
        );

        strokeWidth(2.9);

        line(
            -10,
            5,
            -10,
            0
        );

        line(
            -10,
            0,
            -7,
            -4
        );

        line(
            -7,
            -4,
            -2,
            -5
        );

        line(
            -2,
            -5,
            3,
            -2.5
        );

        line(
            3,
            -2.5,
            4.8,
            1.8
        );

        line(
            4.8,
            1.8,
            2.4,
            4.8
        );

        line(
            2.4,
            4.8,
            -3,
            4.8
        );

        /*
         * 小さな光沢
         */
        stroke(
            255,
            246,
            158,
            alpha * 0.74
        );

        strokeWidth(0.9);

        line(
            -8.5,
            3.5,
            -6.5,
            -2.0
        );

        line(
            -6.5,
            -2.0,
            -1.7,
            -3.2
        );

        line(
            -1.7,
            -3.2,
            2.0,
            -1.5
        );

        noStroke();

        popMatrix();
    };


    /*
     * 4. レモン添えとレモンピールが
     *    両方ある時は、どちらも完成グラスに出す。
     */
    const getFinishedColaFeatureIdsBaseForLemonPeel =
        getFinishedColaFeatureIds;

    getFinishedColaFeatureIds = function() {
        const result =
            gameState.resultData || {};

        const counts =
            result.ingredientCounts || {};

        const garnishes =
            Array.isArray(
                result.garnishes
            )
                ? result.garnishes
                : (
                    result.garnish
                        ? [
                            result.garnish,
                        ]
                        : []
                );

        const hasLemon =
            garnishes.indexOf(
                "lemon"
            ) >= 0;

        const hasLemonPeel =
            (
                counts.lemon_peel ||
                0
            ) > 0;

        if (
            hasLemon &&
            hasLemonPeel
        ) {
            return [
                "lemon",
                "lemon_peel",
            ];
        }

        return getFinishedColaFeatureIdsBaseForLemonPeel();
    };


    /*
     * 5. 結果テキスト
     */
                if (
        RESULT_WORDS &&
        RESULT_WORDS.ja &&
        RESULT_WORDS.ja.topFlavor
    ) {
        RESULT_WORDS.ja.topFlavor.lemon_peel =
            "レモンピール香る";
    }

    if (
        RESULT_WORDS &&
        RESULT_WORDS.en &&
        RESULT_WORDS.en.topFlavor
    ) {
        RESULT_WORDS.en.topFlavor.lemon_peel =
            "Lemon Peel";
    }
}


function installBottleGarnishTrayPlacement() {
    drawPendingBottleGarnish = function(
        geometry
    ) {
        const garnishes =
            getVisibleBottleGarnishes();

        if (
            garnishes.length <= 0
        ) {
            return;
        }

        const effect =
            gameState.ingredientGetEffect;

        const reaction =
            gameState.garnishTrayReaction;

        const activeGarnish =
            effect &&
            effect.visible &&
            effect.kind === "garnish"
                ? effect.garnish
                : (
                    reaction &&
                    reaction.active
                        ? reaction.garnish
                        : null
                );

        const isDouble =
            garnishes.length >= 2;

        const trayScale =
            reaction &&
            reaction.active
                ? reaction.scale
                : 1;

        const trayLift =
            reaction &&
            reaction.active
                ? reaction.lift
                : 0;

        const trayGlow =
            reaction &&
            reaction.active
                ? reaction.glow
                : 0;

        const dishX =
            -geometry.bodyWidth *
            (
                isDouble
                    ? 0.83
                    : 0.78
            );

        const dishY =
            geometry.bodyBottom +
            10;

        const dishW =
            isDouble
                ? 35
                : 24;

        const dishH =
            isDouble
                ? 13
                : 11;

        pushMatrix();

        translate(
            dishX,
            dishY + trayLift
        );

        scale(
            trayScale,
            trayScale
        );

        if (trayGlow > 0) {
            noStroke();

            fill(
                255,
                222,
                143,
                52 * trayGlow
            );

            ellipse(
                0,
                0,
                dishW +
                    12 * trayGlow,
                dishH +
                    10 * trayGlow
            );
        }

        noStroke();

        fill(
            10,
            8,
            7,
            82
        );

        ellipse(
            2,
            -dishH * 0.66,
            dishW * 0.92,
            dishH * 0.66
        );

        fill(
            30,
            19,
            14,
            235
        );

        ellipse(
            0,
            0,
            dishW,
            dishH
        );

        noFill();

        stroke(
            218,
            169,
            99,
            150
        );

        strokeWidth(1.4);

        ellipse(
            0,
            0,
            dishW,
            dishH
        );

        noStroke();

        fill(
            255,
            232,
            190,
            40
        );

        ellipse(
            -dishW * 0.08,
            dishH * 0.10,
            dishW * 0.56,
            dishH * 0.34
        );

        const itemOffsets =
            isDouble
                ? [
                    -dishW * 0.22,
                    dishW * 0.22,
                ]
                : [0];

        for (
            let index = 0;
            index < garnishes.length;
            index += 1
        ) {
            const garnish =
                garnishes[index];

            const isActive =
                garnish ===
                activeGarnish;

            const activePulse =
                isActive
                    ? 1 +
                        Math.sin(
                            ElapsedTime * 15
                        ) *
                            0.045
                    : 1;

            const scaleValue =
                (
                    garnish === "cherry"
                        ? 8.4
                        : 9.0
                ) *
                (
                    isActive
                        ? 1.08 *
                            activePulse
                        : 0.94
                );

            drawGarnishSymbol(
                garnish,
                itemOffsets[index],
                dishH * 0.37,
                scaleValue,
                isActive
                    ? 245
                    : 228,
                garnish === "cherry"
                    ? -16
                    : 10
            );
        }

        popMatrix();

        noStroke();
        rectMode(CORNER);
        ellipseMode(CENTER);
    };
}


function initializeGameFonts() {
    if (
        typeof document !==
        "undefined"
    ) {
        const fontHref =
            "https://fonts.googleapis.com/css2?family=Kaisei+Decol:wght@400;500;700&family=Zen+Kaku+Gothic+New:wght@400;500;700&display=block";

        let fontLink =
            document.getElementById(
                "colaRollGoogleFonts"
            );

        if (!fontLink) {
            fontLink =
                document.createElement(
                    "link"
                );

            fontLink.id =
                "colaRollGoogleFonts";

            fontLink.rel =
                "stylesheet";

            document.head.appendChild(
                fontLink
            );
        }

        fontLink.href =
            fontHref;
    }

    startColaRollFontGate();
    setGameUIFont();
}

function colaRollFontGateCanvas() {
    if (
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx &&
        CodeaLite.state.ctx.canvas
    ) {
        return CodeaLite.state.ctx.canvas;
    }

    if (
        typeof document !==
            "undefined"
    ) {
        return document.querySelector(
            "canvas"
        );
    }

    return null;
}

function startColaRollFontGate() {
    const root =
        typeof globalThis !==
        "undefined"
            ? globalThis
            : (
                typeof window !==
                "undefined"
                    ? window
                    : {}
            );

    if (
        root.__colaRollFontGateStarted
    ) {
        return;
    }

    root.__colaRollFontGateStarted =
        true;

    if (
        typeof document ===
            "undefined"
    ) {
        return;
    }

    const canvas =
        colaRollFontGateCanvas();

    if (!canvas) {
        return;
    }

    const body =
        document.body;

    const documentRoot =
        document.documentElement;

    if (body) {
        body.style.backgroundColor =
            "rgb(24, 14, 10)";
    }

    if (documentRoot) {
        documentRoot.style.backgroundColor =
            "rgb(24, 14, 10)";
    }

    canvas.style.transition =
        "none";

    canvas.style.opacity =
        "0";

    canvas.style.pointerEvents =
        "none";

    /*
     * opacity: 0 を先に確定させてから、
     * 読込完了時だけフェードインさせる。
     */
    void canvas.offsetWidth;

    canvas.style.transition =
        "opacity 0.26s ease";

    let revealed =
        false;

    const startedAt =
        Date.now();

    function revealCanvas() {
        if (revealed) {
            return;
        }

        revealed =
            true;

        const elapsed =
            Date.now() -
            startedAt;

        const minimumWait =
            80;

        const remaining =
            Math.max(
                0,
                minimumWait -
                    elapsed
            );

        setTimeout(
            function() {
                const show =
                    function() {
                        canvas.style.opacity =
                            "1";

                        canvas.style.pointerEvents =
                            "auto";
                    };

                if (
                    typeof requestAnimationFrame ===
                    "function"
                ) {
                    requestAnimationFrame(
                        show
                    );
                } else {
                    show();
                }
            },
            remaining
        );
    }

    if (
        !document.fonts ||
        typeof document.fonts.load !==
            "function"
    ) {
        revealCanvas();
        return;
    }

    const fontJobs = [
        document.fonts.load(
            '400 16px "Kaisei Decol"'
        ),
        document.fonts.load(
            '500 16px "Kaisei Decol"'
        ),
        document.fonts.load(
            '700 16px "Kaisei Decol"'
        ),
        document.fonts.load(
            '400 16px "Zen Kaku Gothic New"'
        ),
        document.fonts.load(
            '500 16px "Zen Kaku Gothic New"'
        ),
        document.fonts.load(
            '700 16px "Zen Kaku Gothic New"'
        ),
    ];

    Promise.all(
        fontJobs
    ).then(
        function() {
            /*
             * Safari 側の描画キャッシュにも
             * 一拍だけ渡してから見せる。
             */
            setTimeout(
                revealCanvas,
                32
            );
        }
    ).catch(
        revealCanvas
    );

    /*
     * 回線不調でフォント取得が止まっても、
     * ずっと暗転したままにはしない。
     */
    setTimeout(
        revealCanvas,
        3200
    );
}



