function resized() {
  updateLayout(true);
}


function draw() {
    try {
        if (
            gameState
        ) {
            gameState.debugLastPhase =
                gameState.phase;
        }

        updateLayout(false);
        drawColaAmbientBackground();

        /*
         * 机はゲーム画面の最初の背景レイヤー。
         * 盤面・瓶・ゲージより先に、一度だけ描く。
         */
        const isGameplayScreen =
            gameState &&
            gameState.phase !== "TITLE" &&
            gameState.phase !==
                "TITLE_TRANSITION" &&
            gameState.phase !== "RESULT";

        if (isGameplayScreen) {
            drawGameplayCounterBehindAll();
        }

        const titleTransitionActive =
            gameState &&
            gameState.titleTransition &&
            gameState.titleTransition.active;

        if (titleTransitionActive) {
            updateTitleStartTransition();
        }

        if (
            typeof updateIngredientGetEffect ===
            "function"
        ) {
            updateIngredientGetEffect();
        }

        if (
            typeof updateCapacitySpillFlow ===
            "function"
        ) {
            updateCapacitySpillFlow();
        }

        if (
            gameState.phase === "TITLE" ||
            gameState.phase ===
                "TITLE_TRANSITION"
        ) {
            drawTitle();
            drawTitleStartTransition();
            drawGameDebugErrorOverlay();
            return;
        }

        updateCarbonationParticles();

        if (gameState.phase === "RESULT") {
            drawGoalResultHandoffUnderlay();
            drawResultScreen();
            drawResultFizzTransition();
            drawTitleStartTransition();
            drawGameDebugErrorOverlay();
            return;
        }

        if (
            gameState.phase ===
            "WAIT_CAP_POWER"
        ) {
            updateCapPower();
        } else if (
            gameState.phase ===
            "CAP_SLIDING"
        ) {
            updateCapSlide();
        } else if (
            gameState.phase ===
            "CAP_PHYSICS"
        ) {
            updateCrownPhysics();
        }

        updateBoardCamera();
        drawPreviewScreen();
        drawTitleStartTransition();
        drawGameDebugErrorOverlay();
    } catch (error) {
        captureGameDebugError(
            error,
            "draw"
        );

        drawEmergencyDebugScreen();
    }
}


function drawGoalResultHandoffUnderlay() {
    const effect =
        gameState.goalEffect;

    if (
        !effect ||
        !effect.visible ||
        effect.stage !== "handoff"
    ) {
        return;
    }

    drawBoardPanel();
    drawGoalArrivalOverlay();
}


function installGameDebugErrorOverlay() {
    if (
        typeof window === "undefined"
    ) {
        return;
    }

    if (
        window.__colaRollDebugInstalled
    ) {
        return;
    }

    window.__colaRollDebugInstalled =
        true;

    window.onerror = function(
        message,
        source,
        lineno,
        colno,
        error
    ) {
        const errorObject =
            error || {
                message:
                    String(
                        message
                    ),
                stack:
                    source
                        ? (
                            String(source) +
                            ":" +
                            String(lineno) +
                            ":" +
                            String(colno)
                        )
                        : "",
            };

        captureGameDebugError(
            errorObject,
            "window.onerror"
        );

        return false;
    };

    window.onunhandledrejection = function(
        event
    ) {
        const reason =
            event && event.reason
                ? event.reason
                : {
                    message:
                        "Unhandled promise rejection",
                    stack:
                        "",
                };

        captureGameDebugError(
            reason,
            "unhandledrejection"
        );
    };
}

function captureGameDebugError(
    error,
    location
) {
    if (!gameState) {
        return;
    }

    const message =
        error && error.message
            ? error.message
            : String(error);

    const stack =
        error && error.stack
            ? String(error.stack)
            : "";

    gameState.debugLastError = {
        message:
            message,
        stack:
            stack,
        location:
            location || "unknown",
        phase:
            gameState.phase || "unknown",
        time:
            typeof ElapsedTime !== "undefined"
                ? ElapsedTime
                : 0,
        slots:
            gameState.glass &&
            gameState.glass.slots
                ? gameState.glass.slots.length
                : -1,
        capacity:
            CONFIG &&
            CONFIG.glassCapacity
                ? CONFIG.glassCapacity
                : -1,
        ingredientEffectKind:
            gameState.ingredientGetEffect
                ? gameState.ingredientGetEffect.kind || ""
                : "",
        ingredientEffectId:
            gameState.ingredientGetEffect
                ? gameState.ingredientGetEffect.ingredientId || ""
                : "",
        ingredientEffectVisible:
            gameState.ingredientGetEffect
                ? !!gameState.ingredientGetEffect.visible
                : false,
    };

    if (
        typeof console !== "undefined" &&
        console.error
    ) {
        console.error(
            "[COLA ROLL DEBUG]",
            gameState.debugLastError
        );
    }
}

