function drawBoardBottleToken(
    x,
    y,
    scaleValue,
    rotationValue,
    alpha
) {
    const width =
        CONFIG.boardBottleWidth;

    const height =
        CONFIG.boardBottleHeight;

    const neckWidth =
        CONFIG.boardBottleNeckWidth;

    const neckHeight =
        CONFIG.boardBottleNeckHeight;

    const mouthWidth =
        CONFIG.boardBottleMouthWidth;

    const mouthHeight =
        CONFIG.boardBottleMouthHeight;

    const mouthInnerWidth =
        CONFIG.boardBottleMouthInnerWidth;

    const mouthInnerHeight =
        CONFIG.boardBottleMouthInnerHeight;

    const slotCount =
        gameState.glass &&
        gameState.glass.slots
            ? gameState.glass.slots.length
            : 0;

    const ingredientRatio =
        Math.max(
            0,
            Math.min(
                1,
                slotCount /
                    CONFIG.glassCapacity
            )
        );

    const pressure =
        gameState.glass
            ? gameState.glass.pressure
            : 0;

    const pressureRatio =
        Math.max(
            0,
            Math.min(
                1,
                pressure /
                    CONFIG.pressureMax
            )
        );

    const liquidRatio =
        0.16 +
        ingredientRatio * 0.72;

    const liquidHeight =
        Math.max(
            4,
            (
                height -
                8
            ) *
                liquidRatio
        );

    const liquidR =
        Math.round(
            154 -
            ingredientRatio * 66
        );

    const liquidG =
        Math.round(
            78 -
            ingredientRatio * 39
        );

    const liquidB =
        Math.round(
            25 -
            ingredientRatio * 10
        );

    const docked =
        !gameState.targetNodeId;

    const screenLift =
        CONFIG.boardBottleScreenLift || 0;

    const shakeActive =
        typeof isEventActionPhase ===
            "function" &&
        isEventActionPhase();

    const shakeOffsetX =
        shakeActive
            ? Math.sin(
                ElapsedTime * 42
            ) * 4
            : 0;

    const shakeRotation =
        shakeActive
            ? Math.sin(
                ElapsedTime * 39
            ) * 6
            : 0;

    if (docked) {
        drawBoardBottleDock(
            x,
            y,
            alpha
        );
    }

    pushMatrix();

    translate(
        x +
            shakeOffsetX,
        y +
            CONFIG.boardBottleRailOffset -
            screenLift
    );

    rotate(
        CONFIG.boardBottleBaseRotation +
            rotationValue +
            shakeRotation
    );

    scale(
        scaleValue,
        scaleValue
    );

    noStroke();

    fill(
        8,
        6,
        5,
        alpha * 0.34
    );

    ellipse(
        3,
        height * 0.48,
        width * 1.55,
        8
    );

    rectMode(CENTER);

    fill(
        18,
        11,
        8,
        alpha * 0.92
    );

    rect(
        2,
        1,
        width + 5,
        height + 4,
        7
    );

    rect(
        2,
        -height * 0.54,
        neckWidth + 4,
        neckHeight + 4,
        3
    );

    fill(
        91,
        51,
        24,
        alpha * 0.92
    );

    rect(
        0,
        0,
        width,
        height,
        6
    );

    fill(
        105,
        61,
        30,
        alpha
    );

    rect(
        0,
        -height * 0.54,
        neckWidth,
        neckHeight,
        2
    );

    fill(
        liquidR,
        liquidG,
        liquidB,
        alpha * 0.94
    );

    rect(
        0,
        height * 0.5 -
            liquidHeight * 0.5 -
            3,
        width - 6,
        liquidHeight,
        4
    );

    fill(
        218,
        151,
        71,
        alpha * 0.42
    );

    rect(
        -width * 0.29,
        -2,
        3,
        height - 10,
        2
    );

    noFill();

    stroke(
        242,
        201,
        132,
        alpha * 0.72
    );

    strokeWidth(1.4);

    rect(
        0,
        0,
        width,
        height,
        6
    );

    rect(
        0,
        -height * 0.54,
        neckWidth,
        neckHeight,
        2
    );

    noStroke();

    const mouthY =
        -height * 0.765;

    const collarY =
        -height * 0.655;

    fill(
        34,
        20,
        14,
        alpha * 0.90
    );

    rect(
        0,
        collarY + 0.4,
        neckWidth + 3.6,
        4.2,
        1.7
    );

    fill(
        132,
        84,
        42,
        alpha
    );

    rect(
        0,
        collarY,
        neckWidth + 2.2,
        3.2,
        1.5
    );

    fill(
        221,
        170,
        95,
        alpha * 0.36
    );

    rect(
        0,
        collarY - 0.3,
        neckWidth - 1.4,
        0.9,
        0.6
    );

    fill(
        45,
        25,
        17,
        alpha
    );

    ellipse(
        0,
        mouthY,
        mouthWidth - 0.6,
        mouthHeight + 0.9
    );

    fill(
        159,
        98,
        48,
        alpha
    );

    ellipse(
        0,
        mouthY + 0.1,
        mouthWidth - 2.4,
        mouthHeight + 0.1
    );

    fill(
        25,
        16,
        11,
        alpha
    );

    ellipse(
        0,
        mouthY + 0.15,
        mouthInnerWidth - 0.4,
        mouthInnerHeight + 0.25
    );

    noFill();

    stroke(
        244,
        193,
        112,
        alpha * 0.82
    );

    strokeWidth(1);

    ellipse(
        0,
        mouthY,
        mouthWidth - 0.5,
        mouthHeight + 0.8
    );

    noStroke();

    fill(
        255,
        230,
        175,
        alpha * 0.34
    );

    ellipse(
        -2.1,
        mouthY - 0.15,
        2.3,
        0.75
    );

    if (pressure > 0) {
        const bubbleCount =
            Math.min(
                5,
                Math.max(
                    1,
                    pressure
                )
            );

        const bubblePositions = [
            {
                x: -5,
                y: 10,
                s: 2.8,
            },
            {
                x: 4,
                y: 7,
                s: 2.2,
            },
            {
                x: -1,
                y: 13,
                s: 2.4,
            },
            {
                x: 6,
                y: 12,
                s: 1.8,
            },
            {
                x: -6,
                y: 4,
                s: 1.9,
            },
        ];

        noFill();

        stroke(
            226,
            244,
            248,
            alpha *
                (
                    0.42 +
                    pressureRatio *
                        0.32
                )
        );

        strokeWidth(1);

        for (
            let index = 0;
            index < bubbleCount;
            index += 1
        ) {
            const bubble =
                bubblePositions[
                    index
                ];

            ellipse(
                bubble.x,
                bubble.y,
                bubble.s
            );
        }

        noStroke();
    }

    rectMode(CORNER);

    popMatrix();

    noStroke();
}



