function updateLayout(force) {
    if (
        !force &&
        WIDTH === lastLayoutWidth &&
        HEIGHT === lastLayoutHeight
    ) {
        return;
    }

    lastLayoutWidth = WIDTH;
    lastLayoutHeight = HEIGHT;

    const portrait =
        HEIGHT > WIDTH;

    if (portrait) {
        const margin = 12;

        const lowerH =
            HEIGHT * 0.38;

        const capW =
            (
                WIDTH -
                margin * 3
            ) *
            0.60;

        const glassW =
            WIDTH -
            capW -
            margin * 3;

        /*
         * まずは通常レイアウトを作る
         */
        layout = {
            board: {
                x: margin,
                y:
                    lowerH +
                    margin * 2,
                w:
                    WIDTH -
                    margin * 2,
                h:
                    HEIGHT -
                    lowerH -
                    margin * 3,
            },

            glass: {
                x: margin,
                y: margin,
                w: glassW,
                h: lowerH,
            },

            cap: {
                x:
                    margin * 2 +
                    glassW,
                y: margin,
                w: capW,
                h: lowerH,
            },
        };

        /*
         * 机の上面位置を求める
         */
        const geometry =
            getBottleInspectionGeometry();

        const counterTopY =
            geometry.centerY +
            geometry.bodyBottom *
                geometry.scale -
            8;

        /*
         * 瓶エリア / ゲージエリアの下端を、
         * 机の少し上へ揃える
         */
        const desiredBottomY =
            counterTopY + 6;

        const glassTopY =
            layout.glass.y +
            layout.glass.h;

        const capTopY =
            layout.cap.y +
            layout.cap.h;

        /*
         * 高さが潰れすぎないよう最小値を確保
         */
        const minGlassH =
            Math.min(
                220,
                lowerH * 0.72
            );

        const minCapH =
            Math.min(
                220,
                lowerH * 0.72
            );

        const maxGlassBottomY =
            glassTopY -
            minGlassH;

        const maxCapBottomY =
            capTopY -
            minCapH;

        const newBottomY =
            Math.min(
                desiredBottomY,
                maxGlassBottomY,
                maxCapBottomY
            );

        layout.glass.y =
            newBottomY;

        layout.glass.h =
            glassTopY -
            newBottomY;

        layout.cap.y =
            newBottomY;

        layout.cap.h =
            capTopY -
            newBottomY;
    } else {
        layout = {
            board: {
                x: 20,
                y:
                    HEIGHT * 0.35 +
                    10,
                w:
                    WIDTH * 0.60,
                h:
                    HEIGHT * 0.65 -
                    30,
            },

            cap: {
                x: 20,
                y: 20,
                w:
                    WIDTH * 0.60,
                h:
                    HEIGHT * 0.35 -
                    20,
            },

            glass: {
                x:
                    WIDTH * 0.60 +
                    40,
                y: 20,
                w:
                    WIDTH * 0.40 -
                    60,
                h:
                    HEIGHT -
                    40,
            },
        };
    }

    CONFIG.mapWidth =
        WIDTH *
        (
            portrait
                ? CONFIG.factoryMapWidthScale
                : 1.30
        );

    CONFIG.mapHeight =
        HEIGHT *
        (
            portrait
                ? CONFIG.factoryMapHeightScale
                : 1.65
        );

    CONFIG.cameraLookAheadY =
        portrait
            ? CONFIG.cameraPortraitLookAheadY
            : CONFIG.cameraLandscapeLookAheadY;

    const currentNode =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!currentNode) {
        return;
    }

    gameState.camera.x =
        currentNode.nx *
        CONFIG.mapWidth;

    gameState.camera.y =
        currentNode.ny *
            CONFIG.mapHeight +
        CONFIG.cameraLookAheadY;

    gameState.camera.zoom =
        portrait
            ? 0.96
            : 1.02;
}


