function drawResultHeaderClean(
    alpha
) {
    const headerY =
        HEIGHT - 43;

    const headerFontSize =
        Math.min(
            24,
            WIDTH * 0.061
        );

    const cardMargin =
        14;

    const maskX =
        cardMargin + 9;

    const maskW =
        WIDTH -
        (
            cardMargin +
            9
        ) *
            2;

    rectMode(CORNER);
    noStroke();

    fill(
        35,
        18,
        12,
        alpha
    );

    rect(
        maskX,
        headerY - 19,
        maskW,
        38,
        4
    );

    if (
        typeof setGameTitleFont ===
        "function"
    ) {
        setGameTitleFont();
    }

    const centerX =
        WIDTH * 0.5;

    const titleHalfWidth =
        headerFontSize *
        3.45;

    const titleGap =
        13;

    const lineWidth =
        Math.min(
            76,
            WIDTH * 0.18
        );

    const leftLineEnd =
        centerX -
        titleHalfWidth -
        titleGap;

    const rightLineStart =
        centerX +
        titleHalfWidth +
        titleGap;

    const leftLineStart =
        Math.max(
            cardMargin + 42,
            leftLineEnd -
                lineWidth
        );

    const rightLineEnd =
        Math.min(
            WIDTH -
                cardMargin -
                42,
            rightLineStart +
                lineWidth
        );

    stroke(
        174,
        101,
        45,
        alpha * 0.75
    );

    strokeWidth(2);

    if (
        leftLineEnd >
        leftLineStart
    ) {
        line(
            leftLineStart,
            headerY,
            leftLineEnd,
            headerY
        );
    }

    if (
        rightLineEnd >
        rightLineStart
    ) {
        line(
            rightLineStart,
            headerY,
            rightLineEnd,
            headerY
        );
    }

    noStroke();

    fill(
        232,
        167,
        73,
        alpha
    );

    fontSize(
        headerFontSize
    );

    textAlign(CENTER);

    text(
        "COLA ROLL",
        centerX,
        headerY
    );

    rectMode(CORNER);
}


function drawResultScreenRefinements() {
    const reveal =
        gameState.resultReveal;

    const alpha =
        reveal
            ? reveal.alpha
            : 255;

    const scaleValue =
        reveal
            ? reveal.scale
            : 1;

    const portrait =
        HEIGHT > WIDTH;

    let textX;
    let nameY;
    let nameMaskW;

    if (portrait) {
        textX =
            WIDTH * 0.5;

        nameY =
            HEIGHT * 0.406;

        nameMaskW =
            WIDTH - 58;
    } else {
        textX =
            WIDTH * 0.72;

        nameY =
            HEIGHT * 0.66;

        nameMaskW =
            WIDTH * 0.46;
    }

    const resultName =
        generateResultName();

    const nameLines =
        splitResultName(
            resultName
        );

    const nameGap =
        portrait
            ? 26
            : 31;

    const nameFontSize =
        portrait
            ? Math.min(
                27,
                WIDTH * 0.066
            )
            : Math.min(
                34,
                WIDTH * 0.041
            );

    const nameStartY =
        nameY +
        (
            nameLines.length -
            1
        ) *
        nameGap *
        0.5;

    const nameMaskH =
        nameFontSize +
        (
            nameLines.length -
            1
        ) *
            nameGap +
        22;

    const button =
        getResultRestartButtonRect();

    pushMatrix();

    translate(
        WIDTH * 0.5,
        HEIGHT * 0.5
    );

    scale(
        scaleValue,
        scaleValue
    );

    translate(
        -WIDTH * 0.5,
        -HEIGHT * 0.5
    );

    /*
     * 上部見出しだけ整える。
     * 結果名に別の札や枠は付けない。
     */
    drawResultHeaderClean(
        alpha
    );

    /*
     * 既存の文字を静かに消すための
     * 最小限の背景マスク。
     */
    rectMode(CENTER);
    noStroke();

    fill(
        35,
        18,
        12,
        alpha
    );

    rect(
        textX,
        nameY,
        nameMaskW,
        nameMaskH,
        4
    );

    /*
     * 結果名は文字そのものを主役にする。
     */
    drawResultNameOrnaments(
        textX,
        nameY,
        portrait,
        nameLines,
        alpha
    );

    setGameTitleFont();

    fontSize(
        nameFontSize
    );

    textAlign(CENTER);

    for (
        let index = 0;
        index <
            nameLines.length;
        index += 1
    ) {
        drawResultLetterpressText(
            nameLines[
                index
            ],
            textX,
            nameStartY -
                index *
                    nameGap,
            alpha
        );
    }

    /*
     * ボタンは既存のまま、
     * 内側の細い線だけ活かす。
     */
    drawResultRestartButtonAccent(
        button,
        alpha
    );

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);

    popMatrix();
}


/*
 * 結果画面の後付け表示を受けるための拡張口。
 *
 * 初期状態では何も描かない。
 * 補充完了など、結果画面の外側にある機能だけが
 * ここへ必要な表示を追加する。
 */
function drawResultScreenPostDraw() {
}

function drawResultScreen() {
    drawResultScreenCore();

    /*
     * 履歴詳細では、再生画面用の戻るボタン。
     * 通常の結果では何も描かない。
     */
    colaHistoryDrawReplayFooter();

    /*
     * 新しい瓶を履歴に保存したことを知らせる短い文。
     */
    colaHistorySavedNote();

    /*
     * 結果画面の見出し・名前・ボタン装飾。
     */
    drawResultScreenRefinements();

    /*
     * 補充完了など、外部機能の結果画面上の表示。
     */
    drawResultScreenPostDraw();
}



function drawResultBottleVisualCodeCore(
    x,
    y,
    scaleValue,
    alpha
) {
    const design =
        getResultBottleLabelDesign();

    const base =
        design.base;

    const light =
        design.light;

    const dark =
        design.dark;

    const labelW =
        68;

    const labelH =
        79;

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    ellipseMode(CENTER);
    noStroke();

    fill(
        18,
        10,
        8,
        alpha * 0.42
    );

    rect(
        2,
        -2,
        labelW + 9,
        labelH + 9,
        11
    );

    fill(
        246,
        220,
        160,
        alpha * 0.92
    );

    rect(
        0,
        0,
        labelW,
        labelH,
        10
    );

    fill(
        base.r,
        base.g,
        base.b,
        alpha * 0.90
    );

    rect(
        0,
        0,
        labelW - 8,
        labelH - 8,
        8
    );

    fill(
        255,
        236,
        185,
        alpha * 0.16
    );

    rect(
        0,
        16,
        labelW - 15,
        18,
        5
    );

    noFill();

    stroke(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.78
    );

    strokeWidth(2);

    rect(
        0,
        0,
        labelW,
        labelH,
        10
    );

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.72
    );

    strokeWidth(1.2);

    rect(
        0,
        0,
        labelW - 13,
        labelH - 13,
        7
    );

    noStroke();

    if (
        design.pattern ===
        "spice"
    ) {
        stroke(
            dark.r,
            dark.g,
            dark.b,
            alpha * 0.42
        );

        strokeWidth(1.6);

        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            const lineY =
                27 -
                index * 17;

            line(
                -28,
                lineY - 6,
                -19,
                lineY + 3
            );

            line(
                19,
                lineY + 3,
                28,
                lineY - 6
            );
        }

        noStroke();
    } else if (
        design.pattern ===
        "fresh"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            alpha * 0.30
        );

        ellipse(
            -23,
            25,
            7
        );

        ellipse(
            24,
            16,
            5
        );

        ellipse(
            -25,
            -22,
            5
        );
    } else if (
        design.pattern ===
        "mystery"
    ) {
        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            pushMatrix();

            translate(
                index % 2 === 0
                    ? -24
                    : 24,
                24 -
                    index * 16
            );

            rotate(45);

            rectMode(CENTER);

            fill(
                light.r,
                light.g,
                light.b,
                alpha * 0.26
            );

            rect(
                0,
                0,
                6,
                6,
                1
            );

            popMatrix();
        }
    } else if (
        design.pattern ===
        "heavy"
    ) {
        fill(
            dark.r,
            dark.g,
            dark.b,
            alpha * 0.28
        );

        rect(
            0,
            25,
            labelW - 18,
            5,
            2
        );

        rect(
            0,
            -25,
            labelW - 18,
            5,
            2
        );
    } else if (
        design.pattern ===
        "drop"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            alpha * 0.28
        );

        ellipse(
            -23,
            23,
            7,
            10
        );

        ellipse(
            24,
            -20,
            6,
            9
        );
    } else {
        noFill();

        stroke(
            light.r,
            light.g,
            light.b,
            alpha * 0.36
        );

        strokeWidth(1.5);

        ellipse(
            -24,
            20,
            8
        );

        ellipse(
            23,
            -20,
            7
        );

        noStroke();
    }

    fill(
        21,
        12,
        10,
        alpha * 0.32
    );

    ellipse(
        0,
        1,
        34,
        34
    );

    drawResultLabelMainMark(
        design,
        alpha
    );

    if (
        design.stillFinish
    ) {
        stroke(
            255,
            236,
            188,
            alpha * 0.62
        );

        strokeWidth(1.6);

        line(
            -22,
            -29,
            22,
            -29
        );

        line(
            -17,
            -24,
            17,
            -24
        );

        noStroke();

        fill(
            255,
            236,
            188,
            alpha * 0.26
        );

        rect(
            0,
            30,
            25,
            4,
            2
        );
    } else {
        const bubbleCount =
            Math.max(
                2,
                Math.min(
                    8,
                    design.carbonationGets +
                    design.pressure +
                    (
                        design.burstCount > 0
                            ? 2
                            : 0
                    )
                )
            );

        for (
            let index = 0;
            index < bubbleCount;
            index += 1
        ) {
            const bubbleX =
                -27 +
                (
                    index % 4
                ) *
                18;

            const bubbleY =
                -28 +
                Math.floor(
                    index / 4
                ) *
                12 +
                (
                    index % 2
                ) *
                3;

            noFill();

            stroke(
                217,
                241,
                247,
                alpha *
                (
                    design.burstCount > 0
                        ? 0.74
                        : 0.54
                )
            );

            strokeWidth(1.2);

            ellipse(
                bubbleX,
                bubbleY,
                4 +
                (
                    index % 3
                )
            );

            noStroke();
        }
    }

    if (
        design.coolingCount > 0
    ) {
        stroke(
            207,
            239,
            247,
            alpha *
            (
                0.44 +
                design.coolingCount * 0.10
            )
        );

        strokeWidth(
            1.2 +
            design.coolingCount * 0.22
        );

        line(
            -25,
            35,
            -13,
            35
        );

        line(
            -19,
            29,
            -19,
            41
        );

        line(
            13,
            35,
            25,
            35
        );

        line(
            19,
            29,
            19,
            41
        );

        noStroke();

        fill(
            210,
            244,
            255,
            alpha * 0.40
        );

        ellipse(
            -28,
            -2,
            4,
            7
        );

        ellipse(
            29,
            12,
            3,
            6
        );
    }

    if (
        design.hasSecret &&
        design.symbol !==
            "diamond"
    ) {
        pushMatrix();

        translate(
            0,
            -31
        );

        rotate(45);

        rectMode(CENTER);

        fill(
            94,
            45,
            119,
            alpha * 0.86
        );

        rect(
            0,
            0,
            8,
            8,
            2
        );

        fill(
            223,
            169,
            236,
            alpha * 0.52
        );

        rect(
            0,
            0,
            3,
            3,
            1
        );

        popMatrix();
    }

    if (
        design.garnish
    ) {
        const markX =
            design.garnish === "cherry"
                ? -25
                : 25;

        const markY =
            -31;

        if (
            design.garnish ===
            "cherry"
        ) {
            fill(
                204,
                56,
                54,
                alpha
            );

            ellipse(
                markX,
                markY,
                8
            );

            fill(
                255,
                158,
                143,
                alpha * 0.72
            );

            ellipse(
                markX - 2,
                markY + 2,
                2.5
            );
        } else {
            noFill();

            stroke(
                227,
                218,
                70,
                alpha
            );

            strokeWidth(2.5);

            ellipse(
                markX,
                markY,
                9
            );

            stroke(
                88,
                130,
                65,
                alpha
            );

            strokeWidth(1.4);

            line(
                markX - 4,
                markY,
                markX + 4,
                markY
            );

            noStroke();
        }
    }

    if (
        design.perfectStopCount > 0
    ) {
        noFill();

        stroke(
            247,
            204,
            104,
            alpha *
            (
                design.perfectGoal
                    ? 0.95
                    : 0.70
            )
        );

        strokeWidth(
            design.perfectGoal
                ? 2.5
                : 1.6
        );

        rect(
            0,
            0,
            labelW - 5,
            labelH - 5,
            8
        );

        if (
            design.perfectGoal
        ) {
            rect(
                0,
                0,
                labelW - 12,
                labelH - 12,
                6
            );
        }

        noStroke();

        const studPositions = [
            {
                x: -28,
                y: 33,
            },
            {
                x: 28,
                y: 33,
            },
            {
                x: -28,
                y: -33,
            },
            {
                x: 28,
                y: -33,
            },
        ];

        for (
            const stud of
            studPositions
        ) {
            fill(
                249,
                214,
                126,
                alpha *
                (
                    design.perfectGoal
                        ? 0.95
                        : 0.72
                )
            );

            ellipse(
                stud.x,
                stud.y,
                design.perfectGoal
                    ? 5
                    : 3.5
            );
        }
    }

    fill(
        18,
        10,
        8,
        alpha * 0.32
    );

    rect(
        0,
        126,
        38,
        13,
        4
    );

    fill(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.90
    );

    rect(
        0,
        126,
        34,
        9,
        3
    );

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.78
    );

    strokeWidth(1.4);

    line(
        -14,
        128,
        14,
        128
    );

    rectMode(CORNER);

    popMatrix();

    noStroke();
}


