function drawSpilledTokens() {
    drawEventSpillDrops();

    const tokens =
        gameState.glass.spilledTokens;

    if (
        !tokens ||
        tokens.length === 0
    ) {
        return;
    }

    const panel =
        layout.glass;

    const startIndex =
        Math.max(
            0,
            tokens.length - 3
        );

    for (
        let index = startIndex;
        index < tokens.length;
        index += 1
    ) {
        const token =
            tokens[index];

        const offset =
            index -
            startIndex;

        const x =
            panel.x +
            panel.w -
            18 -
            offset * 8;

        const y =
            panel.y +
            22 +
            offset * 15;

        pushMatrix();

        translate(
            x,
            y
        );

        rotate(
            35 +
            index * 18
        );

        fill(
            INGREDIENTS[
                token.ingredientId
            ].color
        );

        rectMode(CENTER);

        rect(
            0,
            0,
            24,
            9,
            2
        );

        drawIngredientIcon(
            token.ingredientId,
            0,
            0,
            9,
            255
        );

        rectMode(CORNER);

        popMatrix();
    }
}


function drawEventSpillDrops() {
    const presentation =
        gameState.eventSpillPresentation;

    if (
        !presentation ||
        !presentation.active ||
        !presentation.startedAt
    ) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            presentation.ingredientId
        ];

    if (!ingredient) {
        presentation.active = false;
        return;
    }

    const now =
        typeof ElapsedTime !==
            "undefined"
            ? ElapsedTime
            : presentation.startedAt;

    const elapsed =
        Math.max(
            0,
            now -
                presentation.startedAt
        );

    const duration =
        Math.max(
            0.01,
            presentation.duration ||
                0.46
        );

    if (
        elapsed >
        duration + 0.22
    ) {
        presentation.active = false;
        return;
    }

    const progress =
        Math.max(
            0,
            Math.min(
                1,
                elapsed / duration
            )
        );

    const geometry =
        getBottleInspectionGeometry();

    const direction =
        presentation.direction || 1;

    const mouthX =
        geometry.centerX +
        direction *
            geometry.mouthWidth *
            geometry.scale *
            0.34;

    const mouthY =
        geometry.centerY +
        (
            geometry.neckTop -
            7
        ) *
            geometry.scale;

    noStroke();
    ellipseMode(CENTER);

    for (
        let index = 0;
        index < 3;
        index += 1
    ) {
        const delay =
            index * 0.13;

        const localProgress =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        progress -
                        delay
                    ) /
                    Math.max(
                        0.01,
                        1 - delay
                    )
                )
            );

        if (localProgress <= 0) {
            continue;
        }

        const dropX =
            mouthX +
            direction *
                (
                    9 +
                    28 * localProgress +
                    index * 5
                );

        const dropY =
            mouthY -
            8 -
            42 * localProgress -
            19 *
                localProgress *
                localProgress +
            Math.sin(
                ElapsedTime * 15 +
                index * 2.1
            ) *
                1.5;

        const dropSize =
            6 -
            index * 0.8 +
            Math.sin(
                localProgress *
                Math.PI
            ) *
                1.8;

        const dropAlpha =
            205 *
            (
                1 -
                localProgress * 0.48
            ) *
            Math.min(
                1,
                localProgress * 5
            );

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            dropAlpha * 0.30
        );

        ellipse(
            dropX +
                direction * 1.5,
            dropY - 1.5,
            dropSize * 1.65
        );

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            dropAlpha
        );

        ellipse(
            dropX,
            dropY,
            dropSize
        );

        fill(
            255,
            239,
            205,
            dropAlpha * 0.48
        );

        ellipse(
            dropX -
                direction *
                    dropSize * 0.18,
            dropY +
                dropSize * 0.18,
            Math.max(
                1.2,
                dropSize * 0.28
            )
        );
    }

    noStroke();
}


function drawCapacitySpillTokenOverlay() {
    const flow =
        gameState.capacitySpillFlow;

    if (
        !flow ||
        !flow.active ||
        flow.stage !== "spilling" ||
        !flow.spilled
    ) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            flow.spilled.ingredientId
        ];

    if (!ingredient) {
        return;
    }

    const rawProgress =
        Math.max(
            0,
            Math.min(
                1,
                flow.visualProgress || 0
            )
        );

    const visibleProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    rawProgress -
                    0.10
                ) /
                    0.90
            )
        );

    if (
        visibleProgress <= 0
    ) {
        return;
    }

    const t =
        1 -
        Math.pow(
            1 - visibleProgress,
            2
        );

    const geometry =
        getBottleInspectionGeometry();

    const startY =
        geometry.centerY +
        getGlassSlotLocalY(
            0
        ) *
            geometry.scale;

    const bottleEdgeX =
        geometry.centerX +
        flow.spillDirection *
            geometry.bodyWidth *
            geometry.scale *
            0.34;

    const travelDistance =
        Math.min(
            94,
            layout.glass.w *
                0.52
        );

    const x =
        bottleEdgeX +
        flow.spillDirection *
            (
                8 +
                travelDistance *
                    t
            );

    const y =
        startY -
        8 -
        26 *
            t +
        20 *
            t *
            t;

    const alpha =
        255 *
        Math.min(
            1,
            visibleProgress *
                4
        ) *
        (
            1 -
            t * 0.14
        );

    pushMatrix();

    translate(
        x,
        y
    );

    rotate(
        flow.spillDirection *
            (
                18 +
                42 * t
            )
    );

    scale(
        0.86 +
            0.10 *
                Math.sin(
                    t *
                    Math.PI
                )
    );

    noStroke();

    fill(
        8,
        5,
        3,
        alpha * 0.28
    );

    ellipse(
        5,
        -12,
        43,
        11
    );

    fill(
        ingredient.color.r,
        ingredient.color.g,
        ingredient.color.b,
        alpha
    );

    rectMode(CENTER);

    rect(
        0,
        0,
        42,
        18,
        4
    );

    noFill();

    stroke(
        255,
        228,
        174,
        alpha * 0.68
    );

    strokeWidth(1.3);

    rect(
        0,
        0,
        42,
        18,
        4
    );

    noStroke();

    drawIngredientIcon(
        flow.spilled.ingredientId,
        0,
        0,
        15,
        alpha
    );

    rectMode(CORNER);

    popMatrix();

    const trailCount =
        3;

    for (
        let index = 0;
        index < trailCount;
        index += 1
    ) {
        const trailRatio =
            (
                index + 1
            ) /
            (
                trailCount + 1
            );

        const trailX =
            bottleEdgeX +
            flow.spillDirection *
                (
                    8 +
                    travelDistance *
                        t *
                        trailRatio
                );

        const trailY =
            startY -
            8 -
            26 *
                t *
                trailRatio;

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            alpha *
                (
                    0.22 -
                    index * 0.05
                )
        );

        noStroke();

        ellipse(
            trailX,
            trailY,
            4 -
                index * 0.7
        );
    }

    noStroke();
}


