function getMainGaugeLayout(panel) {
    const radius =
        Math.min(
            panel.w * 0.31,
            panel.h * 0.25
        );

    return {
        centerX:
            panel.w * 0.50,

        centerY:
            panel.h * 0.43,

        radius:
            radius,

        scale: 1,

        sourceCenterX:
            panel.w * 0.50,

        sourceCenterY:
            panel.h * 0.43,
    };
}


