/*
 * 夜の補充先カード。
 *
 * 圧力計の既存フェーズには触れず、
 * startShotGaugeStartup() の直前だけを一度受け止める。
 * カードを閉じた後は、元の圧力計起動処理へそのまま戻す。
 */

/*
 * 補充先と再開の導線。
 * TITLE_TRANSITION → NIGHT_DISPATCH → WAIT_CAP_POWER を一本化する。
 */
function colaRollDispatchText(
    key
) {
    const ja = {
        title: "\u4eca\u591c\u306e\u3054\u6ce8\u6587",
        destination: "\u304a\u5c4a\u3051\u5148",
        request: "\u3054\u5e0c\u671b",
        close: "\u8d77\u52d5\u3059\u308b",
    };

    const en = {
        title: "TONIGHT'S ORDER",
        destination: "DELIVERY TO",
        request: "REQUEST",
        close: "START THE COLA MAKER",
    };

    const table =
        gameState &&
        gameState.language === "en"
            ? en
            : ja;

    return table[key] || "";
}


function colaRollOrderPlaceLines(
    placeText,
    language
) {
    const value =
        typeof placeText === "string"
            ? placeText.trim()
            : "";

    if (
        !value ||
        language !== "en"
    ) {
        return [value];
    }

    const maxLineCharacters =
        18;

    if (
        value.length <=
        maxLineCharacters
    ) {
        return [value];
    }

    const words =
        value.split(/\s+/).filter(
            function(word) {
                return !!word;
            }
        );

    if (words.length <= 1) {
        return [value];
    }

    let best =
        null;

    for (
        let splitIndex = 1;
        splitIndex < words.length;
        splitIndex += 1
    ) {
        const firstLine =
            words.slice(
                0,
                splitIndex
            ).join(" ");

        const secondLine =
            words.slice(
                splitIndex
            ).join(" ");

        const longestLine =
            Math.max(
                firstLine.length,
                secondLine.length
            );

        if (
            longestLine >
            maxLineCharacters
        ) {
            continue;
        }

        const candidate = {
            firstLine: firstLine,
            secondLine: secondLine,
            balance: Math.abs(
                firstLine.length -
                secondLine.length
            ),
            longestLine: longestLine,
        };

        if (
            !best ||
            candidate.balance <
                best.balance ||
            (
                candidate.balance ===
                    best.balance &&
                candidate.longestLine <
                    best.longestLine
            )
        ) {
            best = candidate;
        }
    }

    if (best) {
        return [
            best.firstLine,
            best.secondLine,
        ];
    }

    return [value];
}



function colaRollDispatchPick(
    pool
) {
    return pool[
        Math.floor(
            Math.random() *
            pool.length
        )
    ];
}

