function colaRollDispatchClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

function colaRollDispatchDelta() {
    return Math.max(
        0,
        Math.min(
            0.05,
            typeof DeltaTime === "number"
                ? DeltaTime
                : 0.016
        )
    );
}

function colaRollDispatchNow() {
    return typeof ElapsedTime === "number"
        ? ElapsedTime
        : Date.now() / 1000;
}

function colaRollDispatchHit(
    touch,
    rect
) {
    return (
        touch.x >= rect.x &&
        touch.x <= rect.x + rect.w &&
        touch.y >= rect.y &&
        touch.y <= rect.y + rect.h
    );
}

function colaRollDispatchDrawBackdrop() {
    const stripeCount =
        44;

    const topColor = {
        r: 22,
        g: 18,
        b: 18,
    };

    const middleColor = {
        r: 34,
        g: 22,
        b: 18,
    };

    const bottomColor = {
        r: 53,
        g: 29,
        b: 18,
    };

    rectMode(CORNER);
    noStroke();

    for (
        let index = 0;
        index < stripeCount;
        index += 1
    ) {
        const startRatio =
            index /
            stripeCount;

        const endRatio =
            (
                index + 1
            ) /
            stripeCount;

        const ratio =
            (
                startRatio +
                endRatio
            ) *
            0.5;

        let red;
        let green;
        let blue;

        if (
            ratio < 0.56
        ) {
            const localRatio =
                ratio /
                0.56;

            red =
                topColor.r +
                (
                    middleColor.r -
                    topColor.r
                ) *
                    localRatio;

            green =
                topColor.g +
                (
                    middleColor.g -
                    topColor.g
                ) *
                    localRatio;

            blue =
                topColor.b +
                (
                    middleColor.b -
                    topColor.b
                ) *
                    localRatio;
        } else {
            const localRatio =
                (
                    ratio -
                    0.56
                ) /
                0.44;

            red =
                middleColor.r +
                (
                    bottomColor.r -
                    middleColor.r
                ) *
                    localRatio;

            green =
                middleColor.g +
                (
                    bottomColor.g -
                    middleColor.g
                ) *
                    localRatio;

            blue =
                middleColor.b +
                (
                    bottomColor.b -
                    middleColor.b
                ) *
                    localRatio;
        }

        fill(
            red,
            green,
            blue
        );

        rect(
            0,
            HEIGHT * startRatio,
            WIDTH,
            HEIGHT *
                (
                    endRatio -
                    startRatio
                ) +
                1
        );
    }

    fill(
        73,
        34,
        20,
        32
    );

    rect(
        0,
        HEIGHT * 0.18,
        WIDTH,
        HEIGHT * 0.30
    );

    fill(
        15,
        10,
        9,
        48
    );

    rect(
        0,
        0,
        WIDTH,
        HEIGHT
    );

    noFill();

    stroke(
        79,
        47,
        30,
        155
    );

    strokeWidth(2);

    rect(
        14,
        14,
        WIDTH - 28,
        HEIGHT - 28,
        18
    );

    stroke(
        161,
        101,
        50,
        70
    );

    strokeWidth(1);

    rect(
        22,
        22,
        WIDTH - 44,
        HEIGHT - 44,
        14
    );

    noStroke();
    rectMode(CORNER);
}


